import 'package:flutter/services.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  final FirebaseAuth _auth = FirebaseAuth.instance;
  SharedPreferences _prefs;

  Future<void> initialize() async {
    _prefs = await SharedPreferences.getInstance();
  }

  Future<FirebaseUser> signInAnonymously() async {
    final AuthResult result = await _auth.signInAnonymously();
    final FirebaseUser user = result.user;
    if (user != null) {
      _saveUserData(user);
    }
    return user;
  }

  Future<FirebaseUser> signInWithEmailAndPassword(String email, String password) async {
    final AuthResult result = await _auth.signInWithEmailAndPassword(email: email, password: password);
    final FirebaseUser user = result.user;
    if (user != null) {
      _saveUserData(user);
    }
    return user;
  }

  Future<void> signOut() async {
    await _auth.signOut();
    _prefs.remove('userId');
    _prefs.remove('authToken');
  }

  String get authToken => _prefs.getString('authToken') ?? '';

  int get userId => _prefs.getInt('userId') ?? -1;

  void _saveUserData(FirebaseUser user) {
    if (user != null) {
      _prefs.setInt('userId', user.uid);
      _prefs.setString('authToken', user.toString());
    }
  }
}